const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const twilio = require('twilio');

const app = express();

const PORT = process.env.PORT || 3000;
const SESSION_SECRET = process.env.SESSION_SECRET || 'change-this-session-secret';
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || '';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || '';
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER || '';

const twilioClient =
  TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN
    ? twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN)
    : null;

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

app.use(
  session({
    secret: SESSION_SECRET,
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: false,
      sameSite: 'lax',
      maxAge: 15 * 60 * 1000
    }
  })
);

function generateSixDigitCode() {
  return crypto.randomInt(100000, 1000000).toString();
}

async function sendSms(to, body) {
  if (!twilioClient) {
    console.log(`[DEV SMS] To: ${to} | Message: ${body}`);
    return { sid: 'mock-message-sid' };
  }

  return twilioClient.messages.create({
    body,
    from: TWILIO_PHONE_NUMBER,
    to
  });
}

function ensureSession2FA(req) {
  if (!req.session.twoFactorAuth) {
    req.session.twoFactorAuth = {
      phoneNumber: null,
      code: null,
      expiresAt: null,
      verified: false,
      attempts: 0
    };
  }
  return req.session.twoFactorAuth;
}

app.post('/2fa/send', async (req, res) => {
  try {
    const { phoneNumber } = req.body;

    if (!phoneNumber || typeof phoneNumber !== 'string') {
      return res.status(400).json({ error: 'Valid phoneNumber is required' });
    }

    const twoFA = ensureSession2FA(req);
    const code = generateSixDigitCode();
    const expiresAt = Date.now() + 5 * 60 * 1000;

    twoFA.phoneNumber = phoneNumber;
    twoFA.code = code;
    twoFA.expiresAt = expiresAt;
    twoFA.verified = false;
    twoFA.attempts = 0;

    await sendSms(phoneNumber, `Your verification code is: ${code}`);

    return res.status(200).json({
      message: 'Verification code sent successfully',
      expiresInSeconds: 300
    });
  } catch (error) {
    console.error('Error sending verification code:', error);
    return res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/2fa/verify', (req, res) => {
  const { code } = req.body;
  const twoFA = ensureSession2FA(req);

  if (!twoFA.code || !twoFA.phoneNumber || !twoFA.expiresAt) {
    return res.status(400).json({ error: 'No verification code has been issued' });
  }

  if (Date.now() > twoFA.expiresAt) {
    twoFA.code = null;
    twoFA.expiresAt = null;
    twoFA.verified = false;
    return res.status(400).json({ error: 'Verification code has expired' });
  }

  if (!code || typeof code !== 'string') {
    return res.status(400).json({ error: 'Valid code is required' });
  }

  if (twoFA.attempts >= 5) {
    return res.status(429).json({ error: 'Too many verification attempts' });
  }

  twoFA.attempts += 1;

  if (twoFA.code !== code) {
    return res.status(401).json({ error: 'Invalid verification code' });
  }

  twoFA.verified = true;
  twoFA.code = null;
  twoFA.expiresAt = null;
  twoFA.attempts = 0;

  return res.status(200).json({
    message: 'Two-factor authentication verified successfully',
    verified: true
  });
});

app.get('/2fa/status', (req, res) => {
  const twoFA = ensureSession2FA(req);

  return res.status(200).json({
    verified: !!twoFA.verified,
    phoneNumber: twoFA.phoneNumber,
    hasPendingCode: !!twoFA.code,
    expiresAt: twoFA.expiresAt
  });
});

app.post('/login', async (req, res) => {
  const { username, password, phoneNumber } = req.body;

  if (!username || !password || !phoneNumber) {
    return res.status(400).json({ error: 'username, password, and phoneNumber are required' });
  }

  const credentialsValid = true;

  if (!credentialsValid) {
    return res.status(401).json({ error: 'Invalid username or password' });
  }

  const twoFA = ensureSession2FA(req);
  const code = generateSixDigitCode();

  twoFA.phoneNumber = phoneNumber;
  twoFA.code = code;
  twoFA.expiresAt = Date.now() + 5 * 60 * 1000;
  twoFA.verified = false;
  twoFA.attempts = 0;

  try {
    await sendSms(phoneNumber, `Your login verification code is: ${code}`);
    return res.status(200).json({
      message: 'Primary authentication successful. 2FA code sent.',
      requiresTwoFactor: true
    });
  } catch (error) {
    console.error('Error during login 2FA send:', error);
    return res.status(500).json({ error: 'Failed to send 2FA code' });
  }
});

app.get('/protected', (req, res) => {
  const twoFA = ensureSession2FA(req);

  if (!twoFA.verified) {
    return res.status(403).json({ error: 'Two-factor authentication required' });
  }

  return res.status(200).json({
    message: 'Access granted to protected resource'
  });
});

app.post('/logout', (req, res) => {
  req.session.destroy(err => {
    if (err) {
      return res.status(500).json({ error: 'Failed to logout' });
    }
    return res.status(200).json({ message: 'Logged out successfully' });
  });
});

